mapper.select:
SELECT wa.id, wa.owner_username AS ownerUsername, ua.avatar AS ownerAvatar, wa.title, wa.description, wa.type, wa.status, wa.original_url AS originalUrl, wa.thumb_320_url AS thumb320Url, wa.thumb_720_url AS thumb720Url, wa.thumb_1280_url AS thumb1280Url, vm.duration_ms AS durationMs, vm.frame_rate AS frameRate, wa.tags_text AS tagsText, wa.copyright_info AS copyrightInfo, wa.rating_avg AS ratingAvg, wa.rating_count AS ratingCount, wa.download_count AS downloadCount, wa.apply_count AS applyCount, wa.created_at AS createdAt, wa.published_at AS publishedAt FROM wallpaper_asset wa LEFT JOIN user_account ua ON ua.username = wa.owner_username LEFT JOIN wallpaper_video_meta vm ON vm.wallpaper_id = wa.id WHERE wa.deleted = 0 AND wa.status = 'published'
AND wa.type = #{type}
AND ( wa.title LIKE CONCAT('%', #{keyword}, '%') OR wa.owner_username LIKE CONCAT('%', #{keyword}, '%') OR wa.description LIKE CONCAT('%', #{keyword}, '%') OR wa.tags_text LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY wa.rating_avg DESC, wa.rating_count DESC, wa.id DESC ORDER BY wa.apply_count DESC, wa.download_count DESC, wa.id DESC ORDER BY wa.published_at DESC, wa.id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM wallpaper_asset wa WHERE wa.deleted = 0 AND wa.status = 'published'
AND wa.type = #{type}
AND ( wa.title LIKE CONCAT('%', #{keyword}, '%') OR wa.owner_username LIKE CONCAT('%', #{keyword}, '%') OR wa.description LIKE CONCAT('%', #{keyword}, '%') OR wa.tags_text LIKE CONCAT('%', #{keyword}, '%') )

SELECT wa.id, wa.owner_username AS ownerUsername, ua.avatar AS ownerAvatar, wa.title, wa.description, wa.type, wa.status, wa.original_url AS originalUrl, wa.thumb_320_url AS thumb320Url, wa.thumb_720_url AS thumb720Url, wa.thumb_1280_url AS thumb1280Url, vm.duration_ms AS durationMs, vm.frame_rate AS frameRate, wa.tags_text AS tagsText, wa.copyright_info AS copyrightInfo, wa.rating_avg AS ratingAvg, wa.rating_count AS ratingCount, wa.download_count AS downloadCount, wa.apply_count AS applyCount, wa.created_at AS createdAt, wa.updated_at AS updatedAt, wa.published_at AS publishedAt FROM wallpaper_asset wa LEFT JOIN user_account ua ON ua.username = wa.owner_username LEFT JOIN wallpaper_video_meta vm ON vm.wallpaper_id = wa.id WHERE wa.deleted = 0 AND wa.owner_username = #{ownerUsername}
AND wa.type = #{type}
AND ( wa.title LIKE CONCAT('%', #{keyword}, '%') OR wa.description LIKE CONCAT('%', #{keyword}, '%') OR wa.tags_text LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY wa.rating_avg DESC, wa.rating_count DESC, wa.id DESC ORDER BY wa.apply_count DESC, wa.download_count DESC, wa.id DESC ORDER BY wa.updated_at DESC, wa.id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM wallpaper_asset wa
