FROM wallpaper_report
WHERE wallpaper_id = #{wallpaperId}
  AND reporter_username = #{reporterUsername}
  AND status = 'pending'

SELECT id, wallpaper_id AS wallpaperId, reporter_username AS reporterUsername, reason_type AS reasonType, reason_detail AS reasonDetail, status, resolver_name AS resolverName, resolution_note AS resolutionNote, created_at AS createdAt, resolved_at AS resolvedAt FROM wallpaper_report
WHERE status = #{status}
ORDER BY id DESC LIMIT #{offset}, #{limit}

